func (o *CarModel) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "CarModelVariants":
		rels, ok := retrieved.(CarModelVariantSlice)
		if !ok {
			return fmt.Errorf("carModel cannot load %T as %q", retrieved, name)
		}

		o.R.CarModelVariants = rels
		o.R.Loaded.CarModelVariants = true

		for _, rel := range rels {
			if rel != nil {
				rel.R.CarModel = o
				rel.R.Loaded.CarModel = true
			}
		}
		return nil
	case "ManufacturerCarManufacturer":
		rel, ok := retrieved.(*CarManufacturer)
		if !ok {
			return fmt.Errorf("carModel cannot load %T as %q", retrieved, name)
		}

		o.R.ManufacturerCarManufacturer = rel
		o.R.Loaded.ManufacturerCarManufacturer = true

		if rel != nil {
			rel.R.ManufacturerCarModels = CarModelSlice{o}
		}
		return nil
	default:
		return fmt.Errorf("carModel has no relationship %q", name)
	}
}

