// LoadCarModelVariants loads the carModel's CarModelVariants into the .R struct
func (o *CarModel) LoadCarModelVariants(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.CarModelVariants = nil
	o.R.Loaded.CarModelVariants = false

	related, err := o.CarModelVariants(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, rel := range related {
		rel.R.CarModel = o
		rel.R.Loaded.CarModel = true
	}

	o.R.CarModelVariants = related
	o.R.Loaded.CarModelVariants = true
	return nil
}

// LoadCarModelVariants loads the carModel's CarModelVariants into the .R struct
func (os CarModelSlice) LoadCarModelVariants(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	carModelVariants, err := os.CarModelVariants(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.CarModelVariants = nil
		o.R.Loaded.CarModelVariants = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	carModelByKey := make(map[int32][]*CarModel, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		carModelByKey[o.ID] = append(carModelByKey[o.ID], o)
	}

	for _, rel := range carModelVariants {

		owners, ok := carModelByKey[rel.CarModelID]
		if !ok {
			continue
		}

		for _, o := range owners {

			rel.R.CarModel = o
			rel.R.Loaded.CarModel = true

			o.R.CarModelVariants = append(o.R.CarModelVariants, rel)

		}
	}

	return nil
}

// LoadManufacturerCarManufacturer loads the carModel's ManufacturerCarManufacturer into the .R struct
func (o *CarModel) LoadManufacturerCarManufacturer(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.ManufacturerCarManufacturer = nil
	o.R.Loaded.ManufacturerCarManufacturer = false

	related, err := o.ManufacturerCarManufacturer(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.ManufacturerCarModels = CarModelSlice{o}

	o.R.ManufacturerCarManufacturer = related
	o.R.Loaded.ManufacturerCarManufacturer = true
	return nil
}

// LoadManufacturerCarManufacturer loads the carModel's ManufacturerCarManufacturer into the .R struct
func (os CarModelSlice) LoadManufacturerCarManufacturer(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	carManufacturers, err := os.ManufacturerCarManufacturer(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.ManufacturerCarManufacturer = nil
		o.R.Loaded.ManufacturerCarManufacturer = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	carModelByKey := make(map[int32][]*CarModel, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		carModelByKey[o.ManufacturerID] = append(carModelByKey[o.ManufacturerID], o)
	}

	for _, rel := range carManufacturers {

		owners, ok := carModelByKey[rel.ID]
		if !ok {
			continue
		}

		for _, o := range owners {

			// to-one: keep only the first matching child (matches the previous break)
			if o.R.ManufacturerCarManufacturer != nil {
				continue
			}

			rel.R.ManufacturerCarModels = append(rel.R.ManufacturerCarModels, o)

			o.R.ManufacturerCarManufacturer = rel

		}
	}

	return nil
}

