type carModelCountPreloader struct {
	CarModelVariants func(...bob.Mod[*dialect.SelectQuery]) psql.Preloader
}

func buildCarModelCountPreloader() carModelCountPreloader {
	return carModelCountPreloader{
		CarModelVariants: func(mods ...bob.Mod[*dialect.SelectQuery]) psql.Preloader {
			return countPreloader[*CarModel]("CarModelVariants", func(parent string) bob.Expression {
				// Build a correlated subquery: (SELECT COUNT(*) FROM related WHERE fk = parent.pk)
				if parent == "" {
					parent = CarModels.Alias()
				}

				subqueryMods := []bob.Mod[*dialect.SelectQuery]{
					sm.Columns(psql.Raw("count(*)")),

					sm.From(CarModelVariants.NameAsExpr()),
					sm.Where(psql.Quote(CarModelVariants.Alias(), "car_model_id").EQ(psql.Quote(parent, "id"))),
				}
				subqueryMods = append(subqueryMods, mods...)
				return psql.Group(psql.Select(subqueryMods...).Expression)
			})
		},
	}
}

